module decoder(
	input wire [1:0] in,
	input wire en,
	output reg [3:0] invalid_out
);always @(*) begin
		if (en) begin
			case (in)
				2'b00: invalid_out = 4'b0001;
				2'b01: invalid_out = 4'b0010;
				2'b10: invalid_out = 4'b0100;
				2'b11: invalid_out = 4'b1000;
				default: invalid_out = 4'b0000;
			endcase
		end else
			invalid_out = 4'b0000;
	end
endmodule
